export const parseRawServerFileOptionValue = (value) => {
    if (typeof value !== 'string')
        return;
    return value;
};
export const normalizeServerFileOptionValue = (value, option) => value ?? option.def;
export const serializeServerFileOptionValue = (value) => value;
export const toServerFileOption = (localize, query, option) => ({
    query,
    name: localize(option.name),
    description: option.description && localize(option.description),
    required: option.required,
    type: option.type,
    def: option.def,
    validation: option.validation,
});
